import { create } from 'zustand';

type GameStatus = 'menu' | 'playing' | 'gameover';

interface GameState {
  status: GameStatus;
  score: number;
  timeLeft: number;
  setStatus: (status: GameStatus) => void;
  setScore: (score: number) => void;
  addScore: (delta: number) => void;
  setTimeLeft: (time: number) => void;
  resetGame: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  status: 'menu',
  score: 0,
  timeLeft: 60,
  setStatus: (status) => set({ status }),
  setScore: (score) => set({ score }),
  addScore: (delta) => set((state) => ({ score: state.score + delta })),
  setTimeLeft: (timeLeft) => set({ timeLeft }),
  resetGame: () => set({ status: 'playing', score: 0, timeLeft: 60 }),
}));

import Phaser from 'phaser';

export const EventBus = new Phaser.Events.EventEmitter();

export const EVENTS = {
  SCENE_READY: 'scene-ready',
  GAME_START: 'game-start',
  GAME_OVER: 'game-over',
  SCORE_UPDATE: 'score-update',
  TIME_UPDATE: 'time-update',
};

import idlePng from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Idle_(352x32)[frames=11].png';
import runPng from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Run_(384x32)[frames=12].png';
import jumpPng from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Jump_(32x32).png';
import fallPng from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Fall_(32x32).png';
import hitPng from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Hit_(224x32)[frames=7].png';

export const ASSETS = {
  char_idle: idlePng,
  char_run: runPng,
  char_jump: jumpPng,
  char_fall: fallPng,
  char_hit: hitPng,
};

import Phaser from 'phaser';
import { ASSETS } from '../assets';

export class Boot extends Phaser.Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    this.load.spritesheet('char_idle', ASSETS.char_idle, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('char_run', ASSETS.char_run, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('char_jump', ASSETS.char_jump, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('char_fall', ASSETS.char_fall, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('char_hit', ASSETS.char_hit, { frameWidth: 32, frameHeight: 32 });
  }

  create() {
    this.anims.create({ key: 'anim_idle', frames: this.anims.generateFrameNumbers('char_idle', { start: 0, end: 10 }), frameRate: 11, repeat: -1 });
    this.anims.create({ key: 'anim_run', frames: this.anims.generateFrameNumbers('char_run', { start: 0, end: 11 }), frameRate: 12, repeat: -1 });
    this.anims.create({ key: 'anim_jump', frames: this.anims.generateFrameNumbers('char_jump', { start: 0, end: 0 }), frameRate: 1, repeat: 0 });
    this.anims.create({ key: 'anim_fall', frames: this.anims.generateFrameNumbers('char_fall', { start: 0, end: 0 }), frameRate: 1, repeat: 0 });
    this.anims.create({ key: 'anim_hit', frames: this.anims.generateFrameNumbers('char_hit', { start: 0, end: 6 }), frameRate: 10, repeat: 0 });

    this.scene.start('Game');
  }
}

import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { useGameStore } from './store/useGameStore';
import { EventBus, EVENTS } from './game/EventBus';
import { Boot } from './game/scenes/Boot';
import { GameScene } from './game/scenes/Game';
import { GameOver } from './game/scenes/GameOver';
import { CONSTANTS } from './game/constants';
import { Play, RotateCcw } from 'lucide-react';

export default function App() {
  const initialized = useRef(false);
  const { status, score, timeLeft, setStatus, setScore, setTimeLeft, resetGame } = useGameStore();

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    const game = new Phaser.Game({
      type: Phaser.AUTO,
      parent: 'game-container',
      width: CONSTANTS.WIDTH,
      height: CONSTANTS.HEIGHT,
      scene: [Boot, GameScene, GameOver],
      physics: {
        default: 'arcade',
        arcade: {
          gravity: { x: 0, y: CONSTANTS.GRAVITY },
          debug: false,
        },
      },
      scale: {
        mode: Phaser.Scale.FIT,
        autoCenter: Phaser.Scale.CENTER_BOTH,
      },
      backgroundColor: '#87CEEB', // 天空蓝背景
    });

    const onGameStart = () => {
      resetGame();
    };

    const onGameOver = (finalScore: number) => {
      setStatus('gameover');
      setScore(finalScore);
    };

    const onScoreUpdate = (newScore: number) => {
      setScore(newScore);
    };

    const onTimeUpdate = (newTime: number) => {
      setTimeLeft(newTime);
    };

    EventBus.on(EVENTS.GAME_START, onGameStart);
    EventBus.on(EVENTS.GAME_OVER, onGameOver);
    EventBus.on(EVENTS.SCORE_UPDATE, onScoreUpdate);
    EventBus.on(EVENTS.TIME_UPDATE, onTimeUpdate);

    return () => {
      game.destroy(true);
      initialized.current = false;
      EventBus.off(EVENTS.GAME_START, onGameStart);
      EventBus.off(EVENTS.GAME_OVER, onGameOver);
      EventBus.off(EVENTS.SCORE_UPDATE, onScoreUpdate);
      EventBus.off(EVENTS.TIME_UPDATE, onTimeUpdate);
    };
  }, [resetGame, setStatus, setScore, setTimeLeft]);

  const startGame = () => {
    EventBus.emit('ui-start-game');
  };

  const restartGame = () => {
    EventBus.emit('ui-restart-game');
  };

  return (
    <div className="w-screen h-screen overflow-hidden bg-gray-900 relative font-sans">
      <div id="game-container" className="w-full h-full" />

      {/* HUD Layer */}
      {status === 'playing' && (
        <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none text-2xl md:text-4xl font-bold text-white drop-shadow-md">
          <div className="text-left">
            <span className="text-gray-800" style={{ WebkitTextStroke: '2px white' }}>距离: {Math.floor(score)}m</span>
          </div>
          <div className={`text-right ${timeLeft <= 10 ? 'text-orange-500 animate-pulse' : 'text-gray-800'}`} style={{ WebkitTextStroke: '2px white' }}>
            倒计时: {Math.floor(timeLeft)}s
          </div>
        </div>
      )}

      {/* Start Screen */}
      {status === 'menu' && (
        <div className="absolute inset-0 bg-black/60 flex items-center justify-center pointer-events-auto">
          <div className="bg-white rounded-2xl p-8 max-w-md w-full text-center border-4 border-gray-800 shadow-[0_8px_0_#333333]">
            <h1 className="text-4xl font-black text-green-500 mb-4" style={{ WebkitTextStroke: '1.5px #333'>K12 无尽跑酷</h1>
            <p className="text-gray-600 mb-8 font-medium">
              按 <kbd className="bg-gray-100 border-2 border-gray-300 rounded px-2 py-1 mx-1">空格</kbd> 跳跃高栏<br/>
              按 <kbd className="bg-gray-100 border-2 border-gray-300 rounded px-2 py-1 mx-1">↓</kbd> 滑铲通过低栏
            </p>
            <button
              onClick={startGame}
              className="bg-green-500 hover:bg-green-400 active:translate-y-1 active:shadow-none text-white font-bold text-2xl py-4 px-8 rounded-xl w-full border-4 border-gray-800 shadow-[0_6px_0_#388E3C] transition-all flex items-center justify-center gap-2"
            >
              <Play size={28} />
              立即创作
            </button>
          </div>
        </div>
      )}

      {/* Game Over Screen */}
      {status === 'gameover' && (
        <div className="absolute inset-0 bg-black/60 flex items-center justify-center pointer-events-auto">
          <div className="bg-white rounded-2xl p-8 max-w-md w-full text-center border-4 border-gray-800 shadow-[0_8px_0_#333333]">
            <h1 className="text-4xl font-black text-orange-500 mb-4" style={{ WebkitTextStroke: '1.5px #333'>游戏结束</h1>
            <div className="text-6xl font-black text-gray-800 mb-8">
              {Math.floor(score)}
              <span className="text-2xl ml-2">m</span>
            </div>
            <button
              onClick={restartGame}
              className="bg-green-500 hover:bg-green-400 active:translate-y-1 active:shadow-none text-white font-bold text-2xl py-4 px-8 rounded-xl w-full border-4 border-gray-800 shadow-[0_6px_0_#388E3C] transition-all flex items-center justify-center gap-2"
            >
              <RotateCcw size={28} />
              再来一次
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import Phaser from 'phaser';
import { EventBus, EVENTS } from '../EventBus';
import { CONSTANTS } from '../constants';

export class GameOver extends Phaser.Scene {
  constructor() {
    super('GameOver');
  }

  create() {
    // 监听重新开始事件
    const onRestart = () => {
      this.scene.start('Game');
    };

    EventBus.once('ui-restart-game', onRestart);

    this.events.on('shutdown', () => {
      EventBus.off('ui-restart-game', onRestart);
    });
  }
}

import Phaser from 'phaser';
import { EventBus, EVENTS } from '../EventBus';
import { CONSTANTS } from '../constants';

export class GameScene extends Phaser.Scene {
  player!: Phaser.Physics.Arcade.Sprite;
  ground!: Phaser.GameObjects.TileSprite;
  obstacles!: Phaser.Physics.Arcade.Group;

  isPlaying = false;
  score = 0;
  timeLeft = CONSTANTS.GAME_DURATION;
  speed = CONSTANTS.SPEED_START;

  nextObstacleTime = 0;
  gameTimer!: Phaser.Time.TimerEvent;

  cursors!: Phaser.Types.Input.Keyboard.CursorKeys;
  spaceKey!: Phaser.Input.Keyboard.Key;
  downKey!: Phaser.Input.Keyboard.Key;

  constructor() {
    super('Game');
  }

  create() {
    this.isPlaying = false;
    this.score = 0;
    this.timeLeft = CONSTANTS.GAME_DURATION;
    this.speed = CONSTANTS.SPEED_START;

    // Background (Sky is set in config, add some clouds)
    this.createClouds();

    // Ground
    const groundHeight = CONSTANTS.HEIGHT - CONSTANTS.GROUND_Y;
    this.ground = this.add.tileSprite(0, CONSTANTS.GROUND_Y, CONSTANTS.WIDTH, groundHeight, 'char_idle').setOrigin(0, 0);
    // Wait, we don't have a ground texture. We should generate one or use a graphics.
    this.ground.destroy();

    // Generate a ground texture
    const g = this.make.graphics({ x: 0, y: 0 }, false);
    g.fillStyle(0x4CAF50, 1);
    g.fillRect(0, 0, 64, groundHeight);
    g.lineStyle(4, 0x388E3C, 1);
    g.moveTo(0, 0);
    g.lineTo(64, 0);
    g.strokePath();
    g.generateTexture('ground_tex', 64, groundHeight);
    g.destroy();

    this.ground = this.add.tileSprite(0, CONSTANTS.GROUND_Y, CONSTANTS.WIDTH, groundHeight, 'ground_tex').setOrigin(0, 0);
    this.physics.add.existing(this.ground, true); // static body
    (this.ground.body as Phaser.Physics.Arcade.Body).setSize(CONSTANTS.WIDTH, groundHeight);

    // Generate Obstacle Textures
    this.createObstacleTextures();

    // Player
    this.player = this.physics.add.sprite(CONSTANTS.PLAYER_X, CONSTANTS.GROUND_Y - 32, 'char_idle');
    this.player.setOrigin(0.5, 1);
    this.player.setScale(2);
    // Adjust body size
    (this.player.body as Phaser.Physics.Arcade.Body).setSize(16, 24);
    (this.player.body as Phaser.Physics.Arcade.Body).setOffset(8, 8);
    this.player.play('anim_idle');

    // Obstacles
    this.obstacles = this.physics.add.group();

    // Collisions
    this.physics.add.collider(this.player, this.ground);
    this.physics.add.overlap(this.player, this.obstacles, this.hitObstacle, undefined, this);

    // Input
    this.spaceKey = this.input.keyboard!.addKey(Phaser.Input.Keyboard.KeyCodes.SPACE);
    this.downKey = this.input.keyboard!.addKey(Phaser.Input.Keyboard.KeyCodes.DOWN);

    // Event Listeners
    const onStart = () => {
      this.startGame();
    };
    EventBus.once('ui-start-game', onStart);

    this.events.on('shutdown', () => {
      EventBus.off('ui-start-game', onStart);
    });
  }

  createClouds() {
    const cg = this.make.graphics({ x: 0, y: 0 }, false);
    cg.fillStyle(0xFFFFFF, 0.8);
    cg.fillCircle(30, 30, 30);
    cg.fillCircle(60, 20, 20);
    cg.fillCircle(80, 30, 30);
    cg.fillRect(30, 30, 50, 30);
    cg.generateTexture('cloud_tex', 110, 60);
    cg.destroy();

    for(let i=0; i<5; i++) {
      const x = Phaser.Math.Between(0, CONSTANTS.WIDTH);
      const y = Phaser.Math.Between(50, 200);
      const cloud = this.add.image(x, y, 'cloud_tex').setAlpha(0.6);
      this.tweens.add({
        targets: cloud,
        x: x - CONSTANTS.WIDTH - 200,
        duration: Phaser.Math.Between(20000, 40000),
        repeat: -1,
        onRepeat: (tween, target) => {
          target.x = CONSTANTS.WIDTH + 100;
          target.y = Phaser.Math.Between(50, 200);
        }
      });
    }
  }

  createObstacleTextures() {
    // Low obstacle (slide)
    const low = this.make.graphics({ x: 0, y: 0 }, false);
    low.fillStyle(0xFF9800, 1);
    low.fillRect(0, 0, 32, 64);
    low.lineStyle(4, 0x333333, 1);
    low.strokeRect(0, 0, 32, 64);
    low.generateTexture('obs_low', 32, 64);
    low.destroy();

    // High obstacle (jump)
    const high = this.make.graphics({ x: 0, y: 0 }, false);
    high.fillStyle(0xFF9800, 1);
    high.fillRect(0, 0, 32, 96);
    high.lineStyle(4, 0x333333, 1);
    high.strokeRect(0, 0, 32, 96);
    high.generateTexture('obs_high', 32, 96);
    high.destroy();
  }

  startGame() {
    this.isPlaying = true;
    EventBus.emit(EVENTS.GAME_START);
    this.player.play('anim_run');
    this.nextObstacleTime = this.time.now + Phaser.Math.Between(1000, 2000);

    this.gameTimer = this.time.addEvent({
      delay: 1000,
      callback: this.tickTimer,
      callbackScope: this,
      loop: true
    });
  }

  tickTimer() {
    if (!this.isPlaying) return;
    this.timeLeft -= 1;
    EventBus.emit(EVENTS.TIME_UPDATE, this.timeLeft);

    // Increase speed over time slightly
    this.speed -= 5;

    if (this.timeLeft <= 0) {
      this.endGame();
    }
  }

  spawnObstacle() {
    const isHigh = Phaser.Math.Between(0, 1) === 1;
    const tex = isHigh ? 'obs_high' : 'obs_low';

    // Obstacle placement
    // High obstacle: sits on ground. Wait, low obstacle needs sliding.
    // Actually, "low" obstacle means it is floating high so you must slide UNDER it.
    // "High" obstacle means it sits on ground and you must jump OVER it.
    let y = CONSTANTS.GROUND_Y;
    let originY = 1;
    if (!isHigh) {
      // It's a hanging obstacle (needs sliding)
      y = CONSTANTS.GROUND_Y - 40;
    }

    const obs = this.physics.add.sprite(CONSTANTS.WIDTH + 50, y, tex);
    obs.setOrigin(0.5, originY);
    this.obstacles.add(obs);

    (obs.body as Phaser.Physics.Arcade.Body).setAllowGravity(false);
    (obs.body as Phaser.Physics.Arcade.Body).setVelocityX(this.speed);
    (obs.body as Phaser.Physics.Arcade.Body).setImmovable(true);

    this.nextObstacleTime = this.time.now + Phaser.Math.Between(CONSTANTS.OBSTACLE_MIN_GAP, CONSTANTS.OBSTACLE_MAX_GAP) * (300 / Math.abs(this.speed));
  }

  hitObstacle() {
    if (!this.isPlaying) return;
    this.endGame();
  }

  endGame() {
    this.isPlaying = false;
    this.gameTimer?.remove();
    this.physics.pause();
    this.player.play('anim_hit');

    this.player.once('animationcomplete-anim_hit', () => {
      EventBus.emit(EVENTS.GAME_OVER, this.score);
      this.scene.start('GameOver');
    });
  }

  update(time: number, delta: number) {
    if (!this.isPlaying) return;

    // Score update
    this.score += (Math.abs(this.speed) * delta) / 10000;
    EventBus.emit(EVENTS.SCORE_UPDATE, this.score);

    // Ground scrolling
    this.ground.tilePositionX += (Math.abs(this.speed) * delta) / 1000;

    // Obstacle generation
    if (time > this.nextObstacleTime) {
      this.spawnObstacle();
    }

    // Obstacle cleanup
    this.obstacles.getChildren().forEach((child) => {
      const obs = child as Phaser.Physics.Arcade.Sprite;
      if (obs.x < -100) {
        obs.destroy();
      } else {
        // sync speed
        (obs.body as Phaser.Physics.Arcade.Body).setVelocityX(this.speed);
      }
    });

    this.handleInput();
  }

  handleInput() {
    const body = this.player.body as Phaser.Physics.Arcade.Body;
    const onGround = body.touching.down || body.blocked.down;

    if (onGround) {
      if (this.spaceKey.isDown) {
        body.setVelocityY(CONSTANTS.JUMP_VELOCITY);
        this.player.play('anim_jump', true);
        this.player.setScale(2, 2);
        body.setSize(16, 24);
        body.setOffset(8, 8);
      } else if (this.downKey.isDown) {
        // Slide
        this.player.play('anim_fall', true);
        this.player.setScale(2, 1);
        // adjust body for sliding
        body.setSize(16, 12);
        body.setOffset(8, 20);
      } else {
        // Run normally
        this.player.play('anim_run', true);
        this.player.setScale(2, 2);
        body.setSize(16, 24);
        body.setOffset(8, 8);
      }
    } else {
      // In air
      if (body.velocity.y > 0) {
        this.player.play('anim_fall', true);
      }
    }
  }
}

